int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return *y - *x;
}
int subarrayCompare(const void *a, const void *b) {
    int **x = (int **)a;
    int **y = (int **)b;
    int n = sizeof(x) / sizeof(x[0]);
    for (int i = 0; i < n; i++) {
        if (x[i] < y[i]) return -1;
        if (x[i] > y[i]) return 1;
    }
    return 0;
}
