        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                int subarraySize = j - i + 1;
                subarrays[subarrayIndex] = (int *)malloc(subarraySize * sizeof(int));
                for (int k = 0; k < subarraySize; k++) {
                    subarrays[subarrayIndex][k] = arr[i + k];
