import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int n = sc.nextInt();
            int m = sc.nextInt();
            int[] arr = new int[n];
            for (int i = 0; i < n; i++) arr[i] = sc.nextInt();
            int[][] subarrays = new int[n * (n + 1) / 2][n];
            int subarrayIndex = 0;
            for (int i = 0; i < n; i++) {
                for (int j = i; j < n; j++) {
                    int subarraySize = j - i + 1;
                    int[] subarray = new int[subarraySize];
                    for (int k = 0; k < subarraySize; k++) {
                        subarray[k] = arr[i + k];
                    }
                    Arrays.sort(subarray);
                    for (int k = 0; k < subarraySize; k++) {
                        subarrays[subarrayIndex][k] = subarray[subarraySize - 1 - k];
                    }
                    subarrayIndex++;
                }
            }
            Arrays.sort(subarrays, (a, b) -> {
                int n = a.length;
                for (int i = 0; i < n; i++) {
                    if (a[i] < b[i]) return -1;
                    if (a[i] > b[i]) return 1;
                }
                return 0;
            });
            for (int i = 0; i < m; i++) {
                int p = sc.nextInt();
                System.out.println(subarrays[p - 1][0]);
            }
        }
    }
}

